// zod-schemas skill: the schema IS the type (z.infer), the single source of
// truth. Parsed on read from storage so an old/corrupt row is dropped, not
// trusted.
import { z } from 'zod';

export const doctorSchema = z.object({
  id: z.string().min(1),
  name: z.string().min(1),
  specialty: z.string().min(1),
});

export type Doctor = z.infer<typeof doctorSchema>;

// Fields needed to create a doctor (id is generated by the repository).
export const newDoctorSchema = doctorSchema.omit({ id: true });
export type NewDoctor = z.infer<typeof newDoctorSchema>;
